@using System.Timers
@implements IDisposable
@inject INotificationService NotificationService

<button class="notification-badge" @onclick="OnClick">
    🔔
    @if (_unreadCount > 0)
    {
        <span class="badge">@(_unreadCount > 99 ? "99+" : _unreadCount)</span>
    }
</button>

@code {
    private int _unreadCount;
    private Timer? _pollTimer;

    [Parameter]
    public EventCallback Clicked { get; set; }

    protected override async Task OnInitializedAsync()
    {
        _unreadCount = await NotificationService.GetUnreadCountAsync();

        NotificationService.OnNotificationReceived += HandleNotification;

        _pollTimer = new Timer(30_000);
        _pollTimer.Elapsed += PollUnreadCount;
        _pollTimer.Start();
    }

    private void HandleNotification(Notification notification)
    {
        _unreadCount++;
        InvokeAsync(StateHasChanged);
    }

    private async void PollUnreadCount(object? sender, ElapsedEventArgs e)
    {
        try
        {
            var count = await NotificationService.GetUnreadCountAsync();
            _unreadCount = count;
            await InvokeAsync(StateHasChanged);
        }
        catch
        {
            // Swallow polling errors to keep the timer alive.
        }
    }

    private async Task OnClick()
    {
        await Clicked.InvokeAsync();
    }

    public void Dispose()
    {
        NotificationService.OnNotificationReceived -= HandleNotification;

        if (_pollTimer is not null)
        {
            _pollTimer.Elapsed -= PollUnreadCount;
            _pollTimer.Stop();
            _pollTimer.Dispose();
        }
    }
}

